type User {
  id: ID!
  email: String!
  displayName: String
  createdAt: DateTime!
  updatedAt: DateTime!
}

type AuthPayload {
  token: String!
  user: User!
}

input RegisterInput {
  email: String!
  password: String!
  displayName: String
}

input LoginInput {
  email: String!
  password: String!
}

extend type Mutation {
  register(input: RegisterInput!): AuthPayload!
  login(input: LoginInput!): AuthPayload!
}

extend type Query {
  me: User
}
enum ItemType {
  BOOKMARK
  VOICE_NOTE
  TEXT_NOTE
  DRIVE_DOC
  HIGHLIGHT
  FILE
}

enum ItemStatus {
  PENDING
  PROCESSING
  READY
  ERROR
}

enum SensitivityLevel {
  PUBLIC
  NORMAL
  SENSITIVE
  PRIVATE
}

enum ItemSortField {
  CREATED_AT
  UPDATED_AT
  CAPTURED_AT
  TITLE
}

enum SortDirection {
  ASC
  DESC
}
type Item {
  id: ID!
  type: ItemType!
  status: ItemStatus!
  sensitivity: SensitivityLevel!
  title: String
  contentText: String
  contentUrl: String
  tags: [String!]!
  metadata: JSON!
  autoMetadata: JSON!
  source: String!
  sourceUrl: String
  createdAt: DateTime!
  updatedAt: DateTime!
  capturedAt: DateTime!
}

type SearchResult {
  items: [Item!]!
  total: Int!
  hasMore: Boolean!
}

input ItemFilter {
  types: [ItemType!]
  tags: [String!]
  sensitivity: [SensitivityLevel!]
  source: String
  dateFrom: DateTime
  dateTo: DateTime
  status: [ItemStatus!]
}

input ItemSort {
  field: ItemSortField!
  direction: SortDirection!
}

input BookmarkInput {
  url: String!
  title: String
  selection: String
  referrer: String
  tags: [String!]
  sensitivity: SensitivityLevel
}

input NoteInput {
  title: String
  content: String!
  tags: [String!]
  sensitivity: SensitivityLevel
}

input UpdateItemInput {
  title: String
  tags: [String!]
  sensitivity: SensitivityLevel
}
scalar DateTime
scalar JSON
type Query {
  item(id: ID!): Item
  items(filter: ItemFilter, limit: Int, offset: Int, sort: ItemSort): SearchResult!
  search(query: String!, filter: ItemFilter, limit: Int, threshold: Float): SearchResult!
}

type Mutation {
  captureBookmark(input: BookmarkInput!): Item!
  captureNote(input: NoteInput!): Item!
  updateItem(id: ID!, input: UpdateItemInput!): Item!
  deleteItem(id: ID!): Boolean!
  updateSensitivity(id: ID!, sensitivity: SensitivityLevel!): Item!
  tagItem(id: ID!, tags: [String!]!): Item!
}

